import React, { useEffect, useRef } from 'react';

function DottedSphere({ size = 700, className = '' }) {
  const canvasRef = useRef(null);
  const animationRef = useRef(null);
  const angleRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;

    canvas.width = size * dpr;
    canvas.height = size * dpr;
    ctx.scale(dpr, dpr);

    const centerX = size / 2;
    const centerY = size / 2;

    function draw() {
      ctx.clearRect(0, 0, size, size);

      // Background glow
      const glow = ctx.createRadialGradient(centerX, centerY * 0.9, 0, centerX, centerY * 0.9, size / 2);
      glow.addColorStop(0, 'rgba(99, 102, 241, 0.08)');
      glow.addColorStop(0.6, 'rgba(139, 92, 246, 0.04)');
      glow.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.fillStyle = glow;
      ctx.fillRect(0, 0, size, size);

      const dots = [];
      const rotation = angleRef.current;

      // Tạo 3 lớp elip với góc nghiêng khác nhau
      const layers = [
        { rx: size * 0.42, ry: size * 0.18, tilt: -0.2, offsetY: -20, rings: 14 },
        { rx: size * 0.38, ry: size * 0.28, tilt: 0.3, offsetY: 30, rings: 12 },
        { rx: size * 0.35, ry: size * 0.35, tilt: -0.1, offsetY: 60, rings: 10 },
      ];

      layers.forEach((layer, layerIdx) => {
        for (let ring = 3; ring <= layer.rings; ring++) {
          const scale = ring / layer.rings;
          const rx = layer.rx * scale;
          const ry = layer.ry * scale;
          const numDots = Math.floor(20 + ring * 4);

          for (let i = 0; i < numDots; i++) {
            const angle = (i / numDots) * Math.PI * 2 + rotation * (layerIdx % 2 === 0 ? 1 : -1);

            // Elip position
            let x = Math.cos(angle) * rx;
            let y = Math.sin(angle) * ry;

            // Tilt transform
            const tiltedY = y * Math.cos(layer.tilt) - 20 * Math.sin(layer.tilt);
            const z = y * Math.sin(layer.tilt) + 20 * Math.cos(layer.tilt);

            dots.push({
              x: centerX + x,
              y: centerY + tiltedY + layer.offsetY,
              z: z + layerIdx * 50,
              depth: (z + size / 2) / size,
              layer: layerIdx
            });
          }
        }
      });

      // Sort back to front
      dots.sort((a, b) => a.z - b.z);

      // Draw dots
      dots.forEach(dot => {
        const alpha = 0.2 + dot.depth * 0.5;
        const dotSize = 1.2 + dot.depth * 1.5;

        // Subtle glow
        ctx.beginPath();
        ctx.arc(dot.x, dot.y, dotSize * 2.5, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(139, 92, 246, ${alpha * 0.08})`;
        ctx.fill();

        ctx.beginPath();
        ctx.arc(dot.x, dot.y, dotSize, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(167, 139, 250, ${alpha})`;
        ctx.fill();
      });

      angleRef.current += 0.0015;
      animationRef.current = requestAnimationFrame(draw);
    }

    draw();

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [size]);

  return (
    <div className={`absolute pointer-events-none ${className}`}>
      <canvas 
        ref={canvasRef}
        style={{ width: size, height: size }}
      />
    </div>
  );
}

export default DottedSphere;
